    icon: faInstagram,
  },
  {
    link: 'https://www.linkedin.com/in/angeloaaronkalaw',
    label: 'LinkedIn',
    icon: faLinkedinIn,
  },
  {
    link: 'https://',
    label: 'Angel List',
    icon: faAngellist,
  },
  {
    link: 'https://twitter.com/#',
    label: 'Twitter',
    icon: faTwitter,
  },
  {
    link: 'mailto:angeloaaronkalaw@gmail.com',
    label: 'Email',
    icon: faEnvelope,
  },
];

export default data;
